import React, { useState, useEffect, useRef } from 'react';
import logo from './logo.svg';
import './App.css';

function App() {
  const [displayText, setDisplayText] = useState('');
  const terminalRef = useRef(null);
  const [cursorVisible, setCursorVisible] = useState(false);
  const [underlineVisible, setUnderlineVisible] = useState(false);

  useEffect(() => {
    const terminalOutputs = [
      'Windows PowerShell',
      'Copyright (C) Microsoft Corporation. All rights reserved.',
      '',
      'PS C:\\users\\Admin> ',
    ];

    const textToType = 'My name is Nathaniel';
    let currentTextIndex = 0;

    const typeText = () => {
      if (currentTextIndex < textToType.length) {
        const currentTypedText = textToType.substring(0, currentTextIndex + 1);
        const textWithCursor = terminalOutputs[3] + currentTypedText;
        setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\n' + textWithCursor);
        currentTextIndex++;
        setTimeout(typeText, 200);
      } else {
        setCursorVisible(true);
        setTimeout(() => {
          let newText = '';
          let deleteTextIndex = textToType.length;
          const deleteTextInterval = setInterval(() => {
            newText = textToType.substring(0, deleteTextIndex);
            const textWithCursor = terminalOutputs[3] + newText;
            setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\n' + textWithCursor);
            deleteTextIndex--;
            if (deleteTextIndex < 0) {
              clearInterval(deleteTextInterval);
              setTimeout(() => {
                const newTypedText = 'But people call me Nate.';
                let newTypedTextIndex = 0;
                const typeNewTextInterval = setInterval(() => {
                  newText += newTypedText[newTypedTextIndex];
                  const textWithCursor = terminalOutputs[3] + newText;
                  setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\n' + textWithCursor);
                  newTypedTextIndex++;
                  if (newTypedTextIndex === newTypedText.length) {
                    clearInterval(typeNewTextInterval);
                    setUnderlineVisible(true);
                  }
                }, 200); // Delay between each letter for the new text
              }, 2000); // Delay before starting to type the new text
            }
          }, 100); // Delay between each backspace
        }, 1000); // Delay before showing the underline
      }
    };

    setDisplayText(terminalOutputs.join('\n'));

    terminalRef.current.scrollTop = terminalRef.current.scrollHeight;

    setTimeout(typeText, 2000); // Delay before starting to type

  }, []);

  useEffect(() => {
    let cursorInterval;
    if (cursorVisible) {
      cursorInterval = setInterval(() => {
        setDisplayText((prevText) => {
          if (prevText.endsWith('|')) {
            return prevText.slice(0, -1);
          } else {
            return prevText + '|';
          }
        });
      }, 500); // Cursor blink interval
    }

    return () => {
      clearInterval(cursorInterval);
    };
  }, [cursorVisible]);

  const handleScroll = () => {
    const taskbar = document.querySelector('.taskbar');
    const taskbarApps = document.querySelectorAll('.taskbar-app');
    const scrollY = window.scrollY;

    if (scrollY >= 300) {
      taskbar.classList.add('taskbar-visible');
      taskbarApps.forEach((app, index) => {
        app.style.transitionDelay = `${index * 0.1}s`;
        app.classList.add('taskbar-app-visible');
      });
    } else {
      taskbar.classList.remove('taskbar-visible');
      taskbarApps.forEach((app) => {
        app.style.transitionDelay = '0s';
        app.classList.remove('taskbar-app-visible');
      });
    }
  };

  useEffect(() => {
    window.addEventListener('scroll', handleScroll);

    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  const handleMouseEnter = (event) => {
    const app = event.target;
    app.classList.add('taskbar-app-hover');
  };

  const handleMouseLeave = (event) => {
    const app = event.target;
    app.classList.remove('taskbar-app-hover');
  };

  const handleClick = (event) => {
    const app = event.target;
    const appName = app.innerText;

    if (appName !== activeApp) {
      setActiveApp(appName);
    } else {
      setActiveApp(null);
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <div className="terminal" ref={terminalRef}>
          <pre>
            {displayText}
            {underlineVisible && <span className="underline"></span>}
          </pre>
        </div>
        <div className="taskbar">
          <div
            className="taskbar-app"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
            onClick={handleClick}
          >
            View Github and other projects
          </div>
          <div
            className="taskbar-app"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
            onClick={handleClick}
          >
            About Me
          </div>
          <div
            className="taskbar-app"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
            onClick={handleClick}
          >
            Contact Me
          </div>
        </div>
      </header>
    </div>
  );
}

export default App;
